messages.content:
A `ReplaySubject<T>(n)` buffers the last `n` emissions and replays them to every new subscriber. Contrast with `BehaviorSubject` which replays only the latest value.

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface DomainEvent {
  readonly type: string;
  readonly at: number;
  readonly payload: unknown;
}

// Buffer the last 5 events for late subscribers.
const bus$: ReplaySubject<DomainEvent> = new ReplaySubject<DomainEvent>(5);

// Emit before anyone subscribes.
bus$.next({ type: 'app.boot', at: Date.now(), payload: null });
bus$.next({ type: 'user.login', at: Date.now(), payload: { id: 'u-1' } });
bus$.next({ type: 'cart.add', at: Date.now(), payload: { sku: 'x' } });

// Expose read-only view.
export const events$: Observable<DomainEvent> = bus$.asObservable();

// A subscriber attaching NOW still receives the 3 buffered events.
events$.subscribe((e: DomainEvent) => console.log('replay:', e.type));

export function publish(evt: DomainEvent): void {
  bus$.next(evt);
}
```

Use `new ReplaySubject<T>(bufferSize)` with `bufferSize: 2`. Unlike `BehaviorSubject` which holds just the latest, `ReplaySubject(2)` keeps a sliding window of the two most recent emissions.

```ts
import { ReplaySubject } from 'rxjs';

const ticker$: ReplaySubject<number> = new ReplaySubject<number>(2);

ticker$.next(1);
ticker$.next(2);
ticker$.next(3);

// Late subscriber gets [2, 3] — the last 2 values — then any future emissions.
ticker$.subscribe((v: number) => console.log('got', v));

ticker$.next(4); // also delivered live
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

interface LogLine {
  readonly level: LogLevel;
  readonly message: string;
  readonly at: number;
}

// Keep a rolling 50-line buffer for late subscribers (e.g. DevTools panels).
const sink$: ReplaySubject<LogLine> = new ReplaySubject<LogLine>(50);

export function log(level: LogLevel, message: string): void {
  sink$.next({ level, message, at: Date.now() });
}

// Read-only public view. A BehaviorSubject would only replay the latest line.
export const logs$: Observable<LogLine> = sink$.asObservable();

// Example: some lines emitted before any panel is open.
log('info', 'boot');
log('debug', 'config loaded');

// Later: DevTools attaches and receives buffered history immediately.
logs$.subscribe((line: LogLine) => console.log(`[${line.level}]`, line.message));
```

`ReplaySubject<T>(bufferSize)` stores the last `bufferSize` values it has emitted. Every new subscriber receives that buffered history immediately on subscribe, then live emissions thereafter. With no argument it replays ALL historical values — use a number unless you really want unbounded memory.

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface Notification {
  readonly id: string;
  readonly title: string;
  readonly seen: boolean;
}

const history$: ReplaySubject<Notification> = new ReplaySubject<Notification>(10);

history$.next({ id: 'n1', title: 'Welcome', seen: false });
history$.next({ id: 'n2', title: 'New message', seen: false });

export const notifications$: Observable<Notification> = history$.asObservable();

// A toast component mounting now gets both buffered notifications.
notifications$.subscribe((n: Notification) => console.log('toast:', n.title));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface Token {
  readonly value: string;
  readonly issuedAt: number;
  readonly expiresAt: number;
}

// Last 3 tokens are retained so a silent-refresh job attaching later can
// diff current vs. previous. BehaviorSubject would only keep the newest.
const tokenSink$: ReplaySubject<Token> = new ReplaySubject<Token>(3);

export function rotateToken(t: Token): void {
  tokenSink$.next(t);
}

export const tokens$: Observable<Token> = tokenSink$.asObservable();

rotateToken({ value: 'jwt-1', issuedAt: 1, expiresAt: 60 });
rotateToken({ value: 'jwt-2', issuedAt: 61, expiresAt: 120 });

// Late subscriber receives jwt-1 and jwt-2 immediately, then future rotations.
tokens$.subscribe((t: Token) => console.log('token:', t.value));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface AppError {
  readonly code: string;
  readonly message: string;
  readonly at: number;
}

// ReplaySubject(20) keeps a 20-element ring buffer. Contrast with
// BehaviorSubject which only keeps one "latest" slot.
const sink$: ReplaySubject<AppError> = new ReplaySubject<AppError>(20);

export function reportError(err: AppError): void {
  sink$.next(err);
}

// `.asObservable()` hides `.next`/`.error`/`.complete` from consumers.
export const errors$: Observable<AppError> = sink$.asObservable();
```

Pass a `windowTime` as the second argument: `new ReplaySubject<T>(bufferSize, windowTime)`. Values older than `windowTime` ms are dropped before replay.

```ts
import { ReplaySubject } from 'rxjs';

interface Quote {
  readonly symbol: string;
  readonly price: number;
  readonly at: number;
}

// Keep up to 100 quotes but never older than 60_000 ms.
const quotes$: ReplaySubject<Quote> = new ReplaySubject<Quote>(100, 60_000);

quotes$.next({ symbol: 'AAPL', price: 190, at: Date.now() });

// Subscribers arriving later get only the still-fresh quotes.
quotes$.subscribe((q: Quote) => console.log(q.symbol, q.price));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface CpuSample {
  readonly core: number;
  readonly percent: number;
  readonly at: number;
}

// 60 samples = 60 seconds at 1 Hz sampling. Late chart mounts get instant backfill.
const samples$: ReplaySubject<CpuSample> = new ReplaySubject<CpuSample>(60);

export function record(sample: CpuSample): void {
  samples$.next(sample);
}

export const cpu$: Observable<CpuSample> = samples$.asObservable();

// Producer ticks before any UI attaches:
record({ core: 0, percent: 12.4, at: Date.now() });
record({ core: 0, percent: 13.1, at: Date.now() });

// Chart subscribes later — receives both samples immediately, then live data.
cpu$.subscribe((s: CpuSample) => console.log(s.core, s.percent));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface ChatMessage {
  readonly id: string;
  readonly author: string;
  readonly text: string;
  readonly at: number;
}

const sink$: ReplaySubject<ChatMessage> = new ReplaySubject<ChatMessage>(20);

export function send(msg: ChatMessage): void {
  sink$.next(msg);
}

// Public read-only view — callers can't `.next()` onto it.
export const messages$: Observable<ChatMessage> = sink$.asObservable();

send({ id: 'm1', author: 'ada', text: 'hi', at: 1 });
send({ id: 'm2', author: 'grace', text: 'hey', at: 2 });

// A user joining the room now gets both messages before any new ones.
messages$.subscribe((m: ChatMessage) => console.log(m.author, m.text));
```

`BehaviorSubject<T>(seed)` requires an initial value and always has one; `ReplaySubject<T>(1)` has no seed and replays only after the first `.next()`. For config that's loaded asynchronously (no sensible default), `ReplaySubject(1)` is the better fit — subscribers don't see a bogus seed.

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface AppConfig {
  readonly apiBase: string;
  readonly featureFlags: Readonly<Record<string, boolean>>;
}

const cache$: ReplaySubject<AppConfig> = new ReplaySubject<AppConfig>(1);

export function setConfig(cfg: AppConfig): void {
  cache$.next(cfg);
}

export const config$: Observable<AppConfig> = cache$.asObservable();

// Any module subscribing after setConfig() receives the latest config synchronously.
```

Add replay-of-last-10 to this simple RxJS subject so late subscribers see history:

```ts
import { Subject } from 'rxjs';
interface Tick { n: number }
export const tick$ = new Subject<Tick>();
```

Swap `Subject` for `ReplaySubject<Tick>(10)`. The public API stays the same (`.next(...)` / `.subscribe(...)`), but late joiners now receive the last 10 ticks on subscribe.

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface Tick {
  readonly n: number;
}

const sink$: ReplaySubject<Tick> = new ReplaySubject<Tick>(10);

export function emitTick(t: Tick): void {
  sink$.next(t);
}

// Read-only view so consumers can't accidentally `.next()` onto the stream.
export const tick$: Observable<Tick> = sink$.asObservable();

emitTick({ n: 1 });
emitTick({ n: 2 });

// Subscriber arriving now: sees n=1, n=2, then any future ticks.
tick$.subscribe((t: Tick) => console.log('tick', t.n));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface Command {
  readonly line: string;
  readonly at: number;
  readonly exit: number;
}

// Rolling window of 100. Older commands are evicted as new ones arrive.
const sink$: ReplaySubject<Command> = new ReplaySubject<Command>(100);

export function record(cmd: Command): void {
  sink$.next(cmd);
}

export const history$: Observable<Command> = sink$.asObservable();

record({ line: 'ls', at: 1, exit: 0 });
record({ line: 'cd ..', at: 2, exit: 0 });

// A "history" panel opened later sees both commands immediately.
history$.subscribe((c: Command) => console.log(c.line));
```

With no `bufferSize`, `ReplaySubject<T>()` replays *every* historical value to every new subscriber. That's unbounded memory — only use it when you genuinely need full history (e.g. a short-lived event replay).

```ts
import { ReplaySubject } from 'rxjs';

interface Step {
  readonly id: string;
}

// No bufferSize -> replays ALL past emissions. Be careful with long-running streams.
const all$: ReplaySubject<Step> = new ReplaySubject<Step>();

all$.next({ id: 's1' });
all$.next({ id: 's2' });
all$.next({ id: 's3' });

// Late subscriber receives s1, s2, s3 in order.
all$.subscribe((s: Step) => console.log('replayed:', s.id));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface WsMessage {
  readonly id: number;
  readonly kind: 'quote' | 'trade' | 'heartbeat';
  readonly payload: string;
}

// 25-deep ring buffer. BehaviorSubject would only hold the single newest message.
const sink$: ReplaySubject<WsMessage> = new ReplaySubject<WsMessage>(25);

export function onSocketFrame(msg: WsMessage): void {
  sink$.next(msg);
}

export const messages$: Observable<WsMessage> = sink$.asObservable();

// Simulated traffic before any UI is listening:
onSocketFrame({ id: 1, kind: 'heartbeat', payload: 'ok' });
onSocketFrame({ id: 2, kind: 'quote', payload: 'AAPL 190' });

// A component mounting now receives both frames, then any future ones.
messages$.subscribe((m: WsMessage) => console.log(m.kind, m.payload));
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface UserAction {
  readonly userId: string;
  readonly kind: string;
  readonly at: number;
}

// Unbounded count but values drop after 30_000 ms.
const sink$: ReplaySubject<UserAction> = new ReplaySubject<UserAction>(Infinity, 30_000);

export function track(action: UserAction): void {
  sink$.next(action);
}

export const actions$: Observable<UserAction> = sink$.asObservable();
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

type Severity = 'info' | 'warn' | 'error';

interface Toast {
  readonly id: string;
  readonly severity: Severity;
  readonly body: string;
}

// BehaviorSubject would show only the latest toast; we want the last 3.
const sink$: ReplaySubject<Toast> = new ReplaySubject<Toast>(3);

export function show(t: Toast): void {
  sink$.next(t);
}

export const toasts$: Observable<Toast> = sink$.asObservable();

show({ id: 't1', severity: 'info', body: 'Saved' });
show({ id: 't2', severity: 'warn', body: 'Slow response' });
show({ id: 't3', severity: 'error', body: 'Network lost' });

// ToastHost mounting now replays all three on first tick.
toasts$.subscribe((t: Toast) => console.log(t.severity, t.body));
```

Each subscribe call triggers the replay from scratch for that subscriber — buffers are shared but delivery is per-subscriber.

```ts
import { ReplaySubject } from 'rxjs';

interface Event {
  readonly n: number;
}

const bus$: ReplaySubject<Event> = new ReplaySubject<Event>(3);

bus$.next({ n: 1 });
bus$.next({ n: 2 });

// Subscriber A — gets { n:1 }, { n:2 }.
bus$.subscribe((e: Event) => console.log('A', e.n));

bus$.next({ n: 3 });

// Subscriber B — gets { n:1 }, { n:2 }, { n:3 } replayed immediately, then live.
bus$.subscribe((e: Event) => console.log('B', e.n));

bus$.next({ n: 4 }); // both A and B receive it live.
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface FlagSet {
  readonly [flag: string]: boolean;
}

// ReplaySubject(1): same "latest-wins" semantics as BehaviorSubject,
// but no initial-value requirement — cleaner for async-loaded config.
const cache$: ReplaySubject<FlagSet> = new ReplaySubject<FlagSet>(1);

export function publishFlags(set: FlagSet): void {
  cache$.next(set);
}

export const flags$: Observable<FlagSet> = cache$.asObservable();

publishFlags({ darkMode: true, betaDashboard: false });

// Any subscriber arriving later gets the current flag set synchronously.
flags$.subscribe((s: FlagSet) => console.log('darkMode?', s.darkMode));
```

Refactor this ad-hoc array-backed history into a ReplaySubject-based stream in RxJS v7:

```ts
const history: string[] = [];
export function record(x: string) { history.push(x); }
export function getHistory() { return history.slice(); }
```

The array-backed approach doesn't let consumers react to new entries — they have to poll. A `ReplaySubject<string>(Infinity)` exposes the same backfill semantics plus live updates.

```ts
import { ReplaySubject, Observable } from 'rxjs';

const sink$: ReplaySubject<string> = new ReplaySubject<string>(Infinity);

export function record(x: string): void {
  sink$.next(x);
}

// Subscribe to get the full history AND future emissions. One-shot consumers
// can do `firstValueFrom(history$.pipe(toArray()))` if the stream ever completes.
export const history$: Observable<string> = sink$.asObservable();
```

Add a 10-second time window to this ReplaySubject so stale entries aren't replayed. Here's the current code:

```ts
import { ReplaySubject } from 'rxjs';
export const events$ = new ReplaySubject<string>(100);
```

Pass `windowTime` as the second constructor argument. Values older than 10_000 ms are dropped from the buffer before replay.

```ts
import { ReplaySubject, Observable } from 'rxjs';

// bufferSize=100, windowTime=10_000 ms. Entries are evicted if EITHER limit
// is exceeded — whichever happens first.
const sink$: ReplaySubject<string> = new ReplaySubject<string>(100, 10_000);

export function emit(s: string): void {
  sink$.next(s);
}

export const events$: Observable<string> = sink$.asObservable();
```

`tap` returns the same observable — it's for observation, not transformation. The v7+ object form `tap({ next, error, complete })` replaces the deprecated positional `tap(next, error, complete)`.

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

interface Metric {
  readonly name: string;
  readonly value: number;
}

const source$: Observable<Metric> = of(
  { name: 'latency', value: 42 },
  { name: 'latency', value: 55 }
);

export const logged$: Observable<Metric> = source$.pipe(
  tap({
    next: (m: Metric) => console.log('[metric]', m.name, m.value),
    error: (e: unknown) => console.error('[metric] error', e),
    complete: () => console.log('[metric] complete'),
  }),
  map((m: Metric) => m)
);
```

Use `tap({ next, error, complete })`. The v7 object form supersedes the v6 positional `tap(nextFn, errFn, completeFn)`, which is now deprecated.

```ts
import { of, Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

const numbers$: Observable<number> = of(1, 2, 3);

const observed$: Observable<number> = numbers$.pipe(
  tap({
    next: (v: number) => console.log('next', v),
    error: (e: unknown) => console.error('error', e),
    complete: () => console.log('done'),
  })
);

observed$.subscribe();
```

```ts
import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

export function logTap<T>(label: string): OperatorFunction<T, T> {
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      tap({
        next: (v: T) => console.log(`[${label}] next`, v),
        error: (e: unknown) => console.error(`[${label}] error`, e),
        complete: () => console.log(`[${label}] complete`),
      })
    );
}

// Usage:
// of(1, 2, 3).pipe(logTap<number>('nums'), map(x => x * 2)).subscribe();
```

Because `OperatorFunction<T, T>` preserves the element type, this composes without type annotations at call sites.

`map` returns a new observable of the transformed values; `tap` returns the *same* observable and exists purely for side effects. A misused `tap` can't corrupt the stream — that's the point.

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

interface Order {
  readonly id: string;
  readonly total: number;
}

const orders$: Observable<Order> = of(
  { id: 'o1', total: 10 },
  { id: 'o2', total: 25 }
);

export const enriched$: Observable<{ readonly id: string; readonly totalCents: number }> =
  orders$.pipe(
    tap({
      next: (o: Order) => console.log('received', o.id),
      error: (e: unknown) => console.error('stream error', e),
      complete: () => console.log('all orders processed'),
    }),
    map((o: Order) => ({ id: o.id, totalCents: o.total * 100 }))
  );
```

Convert this deprecated positional tap call to the v7+ object form:

```ts
import { of } from 'rxjs';
import { tap } from 'rxjs/operators';
of(1,2,3).pipe(tap(v => console.log(v), e => console.error(e), () => console.log('done'))).subscribe();
```

The positional `tap(nextFn, errFn, completeFn)` signature is deprecated in v7. Pass an observer object instead.

```ts
import { of, Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

const stream$: Observable<number> = of(1, 2, 3);

stream$
  .pipe(
    tap({
      next: (v: number) => console.log(v),
      error: (e: unknown) => console.error(e),
      complete: () => console.log('done'),
    })
  )
  .subscribe();
```

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

interface Response {
  readonly status: number;
  readonly bodyBytes: number;
}

interface Parsed {
  readonly ok: boolean;
  readonly bytes: number;
}

declare function incCounter(name: string): void;
declare function track(err: unknown): void;
declare function markComplete(): void;

const responses$: Observable<Response> = of(
  { status: 200, bodyBytes: 512 },
  { status: 200, bodyBytes: 1024 }
);

export const parsed$: Observable<Parsed> = responses$.pipe(
  tap({
    next: (r: Response) => incCounter(`status.${r.status}`),
    error: (e: unknown) => track(e),
    complete: () => markComplete(),
  }),
  map((r: Response) => ({ ok: r.status < 400, bytes: r.bodyBytes }))
);
```

Add observability via tap({ next, error, complete }) to this pipeline in RxJS v7:

```ts
import { of } from 'rxjs';
import { map } from 'rxjs/operators';
of(1,2,3).pipe(map(x => x * 2)).subscribe(console.log);
```

Place `tap` BEFORE the terminal `subscribe`. Putting it before `map` observes raw values; putting it after observes doubled values. Either is fine — pick based on what you want to watch.

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

const stream$: Observable<number> = of(1, 2, 3);

stream$
  .pipe(
    tap({
      next: (v: number) => console.log('raw', v),
      error: (e: unknown) => console.error('err', e),
      complete: () => console.log('done'),
    }),
    map((x: number) => x * 2)
  )
  .subscribe((v: number) => console.log('doubled', v));
```

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

type EventKind = 'click' | 'view' | 'purchase';

interface UserEvent {
  readonly userId: string;
  readonly kind: EventKind;
  readonly at: number;
}

interface Enriched {
  readonly userId: string;
  readonly kind: EventKind;
  readonly hourBucket: number;
}

const seed: readonly UserEvent[] = [
  { userId: 'u1', kind: 'click', at: 1_700_000_000_000 },
  { userId: 'u1', kind: 'purchase', at: 1_700_003_600_000 },
];
const events$: Observable<UserEvent> = of(...seed);

export const enriched$: Observable<Enriched> = events$.pipe(
  tap({
    next: (e: UserEvent) => console.log('seen', e.userId, e.kind),
    error: (err: unknown) => console.error('stream failed', err),
    complete: () => console.log('end of events'),
  }),
  map((e: UserEvent): Enriched => ({
    userId: e.userId,
    kind: e.kind,
    hourBucket: Math.floor(e.at / 3_600_000),
  }))
);
```

```ts
import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

export function debugProbe<T>(tag: string): OperatorFunction<T, T> {
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      tap({
        next: (v: T) => console.debug(`${tag} →`, v),
        error: (e: unknown) => console.error(`${tag} ✗`, e),
        complete: () => console.debug(`${tag} ✓ complete`),
      })
    );
}

// Example usage — tap is observation-only; the downstream type is unchanged.
// import { of } from 'rxjs';
// of('a', 'b').pipe(debugProbe<string>('letters')).subscribe();
```

Use `tap({ error })` — the error still propagates downstream (tap never handles it). If you wanted to recover, you'd use `catchError`; `tap` is for pure observation.

```ts
import { throwError, Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

const bad$: Observable<number> = throwError(() => new Error('boom'));

bad$
  .pipe(
    tap({
      next: (v: number) => console.log('value', v),
      error: (e: unknown) => console.error('saw error (will still propagate):', e),
      complete: () => console.log('complete (never runs here)'),
    })
  )
  .subscribe({
    error: (e: unknown) => console.error('subscriber sees it too:', e),
  });
```

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

interface Command {
  readonly id: string;
  readonly op: 'create' | 'update' | 'delete';
}

interface Audit {
  readonly id: string;
  readonly op: Command['op'];
  readonly at: number;
}

declare function writeAudit(row: Audit): void;
declare function captureError(e: unknown): void;

const seed: readonly Command[] = [
  { id: 'c1', op: 'create' },
  { id: 'c2', op: 'update' },
];
const cmds$: Observable<Command> = of(...seed);

export const audited$: Observable<Command> = cmds$.pipe(
  tap({
    next: (c: Command) => writeAudit({ id: c.id, op: c.op, at: Date.now() }),
    error: (e: unknown) => captureError(e),
    complete: () => console.log('audit stream complete'),
  }),
  map((c: Command) => c)
);
```

Place `tap` anywhere in a `.pipe(...)` chain — its position decides *what* you observe: values before or after preceding transforms. Just put it BEFORE the terminal `subscribe()`. `tap` is observation-only; it never alters the element type.

```ts
import { of, Observable } from 'rxjs';
import { tap, map, filter } from 'rxjs/operators';

const nums$: Observable<number> = of(1, 2, 3, 4);

export const pipeline$: Observable<number> = nums$.pipe(
  filter((n: number) => n % 2 === 0),
  tap({
    next: (n: number) => console.log('even seen', n),
    error: (e: unknown) => console.error(e),
    complete: () => console.log('no more evens'),
  }),
  map((n: number) => n * 10)
);
```

Refactor this v6-style pipeline to v7 idioms. Use tap with the observer object form and type everything. Snippet:

```ts
import { of } from 'rxjs';
import { tap, map } from 'rxjs/operators';
of('a','b').pipe(tap(v=>console.log(v), e=>console.error(e), ()=>console.log('!')), map(s=>s.toUpperCase())).subscribe();
```

```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

const letters$: Observable<string> = of('a', 'b');

letters$
  .pipe(
    tap({
      next: (v: string) => console.log(v),
      error: (e: unknown) => console.error(e),
      complete: () => console.log('!'),
    }),
    map((s: string) => s.toUpperCase())
  )
  .subscribe();
```

The positional `tap(next, err, complete)` overload was deprecated in v7 in favour of the observer-shaped `tap({ next, error, complete })`.

```ts
import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

interface PageView {
  readonly path: string;
  readonly referrer: string | null;
}

declare const analytics: {
  send(evt: PageView): void;
  fail(e: unknown): void;
  flush(): void;
};

export function reportPageViews(): OperatorFunction<PageView, PageView> {
  return (source$: Observable<PageView>): Observable<PageView> =>
    source$.pipe(
      tap({
        next: (pv: PageView) => analytics.send(pv),
        error: (e: unknown) => analytics.fail(e),
        complete: () => analytics.flush(),
      })
    );
}
```

Use the `complete` handler of `tap({ next, error, complete })`. It fires once, when the source emits a completion notification.

```ts
import { of, Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

declare function closeConnection(): void;

const rows$: Observable<number> = of(1, 2, 3);

rows$
  .pipe(
    tap({
      next: (r: number) => console.log('row', r),
      error: (e: unknown) => console.error('row error', e),
      complete: () => {
        console.log('all rows read');
        closeConnection();
      },
    })
  )
  .subscribe();
```

Every field on the `tap` observer is optional. Provide only what you need.

