interface Payload {
  readonly id: string;
}

const source$: Observable<Payload> = of({ id: 'p1' }, { id: 'p2' });

export const watched$: Observable<string> = source$.pipe(
  tap({
    next: (p: Payload) => console.log('seen', p.id),
    error: (e: unknown) => console.error('oops', e),
