```ts
import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

interface Span {
  readonly traceId: string;
  readonly kind: 'next' | 'error' | 'complete';
  readonly at: number;
}

declare function emitSpan(s: Span): void;

export function traceStream<T>(traceId: string): OperatorFunction<T, T> {
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      tap({
        next: (_v: T) => emitSpan({ traceId, kind: 'next', at: Date.now() }),
        error: (_e: unknown) => emitSpan({ traceId, kind: 'error', at: Date.now() }),
        complete: () => emitSpan({ traceId, kind: 'complete', at: Date.now() }),
      })
    );
}
