```ts
import { of, Observable } from 'rxjs';
import { tap, map } from 'rxjs/operators';

const input$: Observable<number> = of(10, 20, 30);

export const pipeline$: Observable<number> = input$.pipe(
  tap({
    next: (v: number) => console.log('pre-map', v),
    error: (e: unknown) => console.error('pre-map err', e),
    complete: () => console.log('pre-map done'),
  }),
  map((v: number) => v + 1),
  tap({
    next: (v: number) => console.log('post-map', v),
    error: (e: unknown) => console.error('post-map err', e),
    complete: () => console.log('post-map done'),
  })
);
```

The two `tap` blocks observe different snapshots — the first sees 10, 20, 30; the second sees 11, 21, 31. Neither changes the stream.

`tap`'s `error` handler fires every time an error flows through it — which means on every retry attempt when paired with `retry`. That makes `tap({ error })` a natural spot for per-attempt logging without changing the stream's shape.

```ts
import { throwError, Observable } from 'rxjs';
import { tap, retry } from 'rxjs/operators';

const flaky$: Observable<number> = throwError(() => new Error('nope'));

flaky$
  .pipe(
    tap({
      next: (v: number) => console.log('value', v),
      error: (e: unknown) => console.warn('attempt failed:', e),
      complete: () => console.log('succeeded'),
    }),
    retry({ count: 2, delay: 100 })
  )
  .subscribe({
    error: (e: unknown) => console.error('gave up:', e),
  });
```

