import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

interface TelemetryHooks {
  readonly onNext: (count: number) => void;
  readonly onError: (err: unknown) => void;
  readonly onComplete: (total: number) => void;
}

export function telemetry<T>(hooks: TelemetryHooks): OperatorFunction<T, T> {
  let count = 0;
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      tap({
        next: (_v: T) => {
          count += 1;
          hooks.onNext(count);
        },
        error: (e: unknown) => hooks.onError(e),
        complete: () => hooks.onComplete(count),
      })
    );
}

